import{_ as t,o as a,c as o,a0 as r}from"./chunks/framework.DgPozsi0.js";const m=JSON.parse('{"title":"[React官網] React 19.2 教程","description":"","frontmatter":{"title":"[React官網] React 19.2 教程"},"headers":[],"relativePath":"pages/f2e/docReact/reactDev/03/reactDev_03_01.md","filePath":"pages/f2e/docReact/reactDev/03/reactDev_03_01.md"}'),l={name:"pages/f2e/docReact/reactDev/03/reactDev_03_01.md"};function c(i,e,d,n,s,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="編輯器設定" tabindex="-1">編輯器設定 <a class="header-anchor" href="#編輯器設定" aria-label="Permalink to &quot;編輯器設定&quot;">​</a></h1><p>正確的編輯器配置可以讓開發事半功倍，並且還可以在編碼時幫你提示錯誤！如果這是你第一次配置編輯器，或者想對現有編輯器進行調整，我們有一些建議可供參考。</p><div class="info custom-block"><p class="custom-block-title">你將學到</p><ul><li>最受歡迎的編輯器是哪些</li><li>如何自動格式化你的代碼</li></ul></div><h2 id="你的編輯器" tabindex="-1">你的編輯器 <a class="header-anchor" href="#你的編輯器" aria-label="Permalink to &quot;你的編輯器&quot;">​</a></h2><p><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">VS Code</a> 是現今最流行的編輯器之一。它擁有龐大的擴充功能市場，同時可以與 <code>GitHub</code> 等流行服務完美集成。 下面列出的大多數功能都可以作為擴充功能添加到 <code>VS Code</code> 中，使其具有極高的可配置性！</p><p><code>React</code> 社群中其他較為流行的文本編輯器包括：</p><ul><li><a href="https://www.jetbrains.com/webstorm/" target="_blank" rel="noreferrer">WebStorm</a>：專為 <code>JavaScript</code> 設計的集成開發環境（IDE）。</li><li><a href="https://www.sublimetext.com/" target="_blank" rel="noreferrer">Sublime Text</a>：支持 <code>JSX</code> 和 <code>TypeScript</code>，內置語法高亮和代碼自動補全功能。</li><li><a href="https://www.vim.org/" target="_blank" rel="noreferrer">Vim</a>：一個高度可配置的文本編輯器，可以非常高效地創建和更改任何類型的文本。它作為 <code>“vi”</code> 包含在大多數 <code>UNIX</code> 系統和 <code>Apple OS X</code> 中。</li></ul><h2 id="推薦的文本編輯器功能" tabindex="-1">推薦的文本編輯器功能 <a class="header-anchor" href="#推薦的文本編輯器功能" aria-label="Permalink to &quot;推薦的文本編輯器功能&quot;">​</a></h2><p>有些編輯器內置了這些功能，但某些編輯器可能需要添加擴充功能。你需要確認你的編輯器支持了哪些能力。</p><ul><li><h3 id="代碼檢查-linting" tabindex="-1">代碼檢查（Linting） <a class="header-anchor" href="#代碼檢查-linting" aria-label="Permalink to &quot;代碼檢查（Linting）&quot;">​</a></h3><p>代碼檢查工具（<code>Code linters</code>）可以在你編寫代碼時發現代碼中的問題，以幫你儘早修復。<a href="https://eslint.org/" target="_blank" rel="noreferrer">ESLint</a> 是一款流行且開源的 <code>JavaScript</code> 代碼檢查工具。</p><ul><li><p>可以使用 React 的 <a href="https://www.npmjs.com/package/eslint-config-react-app" target="_blank" rel="noreferrer">推薦配置安裝 ESLint</a>（需確保已安裝 Node）。</p></li><li><p>可安裝 VSCode 中的 <a href="https://marketplace.visualstudio.com/items?itemName=dbaeumer.vscode-eslint" target="_blank" rel="noreferrer">官方 ESLint 擴充功能</a>。</p></li><li><h4 id="必備規則提醒" tabindex="-1">必備規則提醒 <a class="header-anchor" href="#必備規則提醒" aria-label="Permalink to &quot;必備規則提醒&quot;">​</a></h4><p>請確保你已經為你的項目啟用了 <a href="https://www.npmjs.com/package/eslint-plugin-react-hooks" target="_blank" rel="noreferrer">eslint-plugin-react-hooks</a> 規則。這在 <code>React</code> 項目中是必備的，同時能幫助你及早捕獲較為嚴重的 <code>bug</code>。官方推薦的 <a href="https://www.npmjs.com/package/eslint-config-react-app" target="_blank" rel="noreferrer">eslint-config-react-app</a> 預設（<code>preset</code>）中已經集成了該規則。</p></li></ul></li><li><h3 id="格式化" tabindex="-1">格式化 <a class="header-anchor" href="#格式化" aria-label="Permalink to &quot;格式化&quot;">​</a></h3><p>與其他貢獻者共享代碼時，為了避免爭論代碼縮進應該使用 <code>tabs</code> 還是空格，可以使用 <a href="https://prettier.io/" target="_blank" rel="noreferrer">Prettier</a>。它會根據預設配置的規則重新格式化代碼（如將 <code>tabs</code> 轉換為空格、規範縮進和引號等），以保證代碼整潔。</p><ul><li><p><a href="https://marketplace.visualstudio.com/items?itemName=esbenp.prettier-vscode" target="_blank" rel="noreferrer">VSCode 安裝 Prettier 擴充</a> 功能步驟：</p><ol><li>啟動 <code>VS Code</code></li><li>使用快速打開（快捷鍵 <code>Ctrl/Cmd + P</code>）</li><li>輸入 <code>ext install esbenp.prettier-vscode</code></li><li>按下 <code>Enter</code></li></ol></li><li><h4 id="保存並自動格式化" tabindex="-1">保存並自動格式化 <a class="header-anchor" href="#保存並自動格式化" aria-label="Permalink to &quot;保存並自動格式化&quot;">​</a></h4><p>理想情況下，你應該在每次保存時自動格式化代碼。</p><ul><li><code>VS Code</code> 的配置步驟如下： <ol><li>在 <code>VS Code</code> 中，按快捷鍵 <code>Ctrl/Cmd + Shift + P</code></li><li>輸入 <code>settings</code></li><li>按下 <code>Enter</code></li><li>在搜索欄輸入 <code>format on save</code></li><li>確保勾選 <code>format on save</code> 選項！</li></ol></li></ul></li></ul><div class="info custom-block"><p class="custom-block-title">衝突隱患提示</p><ul><li>如果你的 <code>ESLint</code> 預設包含格式化規則，它們可能會與 <code>Prettier</code> 發生衝突。</li><li>建議使用 <code>eslint-config-prettier</code> 禁用 <code>ESLint</code> 預設中的所有格式化規則，讓 <code>ESLint</code> 只用於捕捉邏輯錯誤。</li><li>如果你想在合併 <code>PR</code> 前強制執行文件的格式化，請在你的 <code>CI</code>（持續集成）中使用 <code>prettier --check</code> 命令。</li></ul></div></li></ul>',10)])])}const u=t(l,[["render",c]]);export{m as __pageData,u as default};
